1	'use client';
2	
3	import { type ReactElement, useCallback, useMemo, useState } from 'react';
4	
5	import { AnimatePresence, motion } from 'framer-motion';
6	
7	// Layout components
8	import ReportsDateFilters from '@/components/CMS/reports/ReportsDateFilters';
9	import ReportsNavigation from '@/components/CMS/reports/ReportsNavigation';
10	import {
11	  ReportsPageAccessDeniedState,
12	  ReportsPageAuthLoadingState,
13	  ReportsPageLoadingOverlay,
14	} from '@/components/CMS/reports/ReportsPageLoadingStates';
15	import ReportsLocationsTabWithErrorHandling from '@/components/CMS/reports/tabs/locations/ReportsLocationsTabWithErrorHandling';
16	import ReportsMachinesTab from '@/components/CMS/reports/tabs/machines/ReportsMachinesTab';
17	import ReportsMetersTab from '@/components/CMS/reports/tabs/meters/ReportsMetersTab';
18	import PageLayout from '@/components/shared/layout/PageLayout';
19	import {
20	  IMAGES,
21	  REPORTS_ANIMATIONS,
22	  REPORTS_TABS_CONFIG,
23	} from '@/lib/constants';
24	import { useReportsTabContent } from '@/lib/hooks/data';
25	import { useReportsNavigation } from '@/lib/hooks/navigation';
26	import { useDashBoardStore } from '@/lib/store/dashboardStore';
27	import { useUserStore } from '@/lib/store/userStore';
28	import type { ReportView } from '@/shared/types/reports';
29	import Image from 'next/image';
30	
31	/**
32	 * Reports Page Content Component
33	 * Main content component for the reports page with tab navigation and layout.
34	 *
35	 * Features:
36	 * - Tab-based navigation (Locations, Machines, Meters)
37	 * - Licencee selection integration
38	 * - Date filters
39	 * - Tab content rendering with suspense
40	 * - Loading states and overlays
41	 * - Access denied states
42	 * - Framer Motion animations
43	 * - Responsive layout
44	 */
45	export default function ReportsPageContent() {
46	  // ============================================================================
47	  // State & Hooks
48	  // ============================================================================
49	  const { selectedLicencee, setSelectedLicencee } = useDashBoardStore();
50	  const { user } = useUserStore();
51	
52	  // Check user roles
53	  const userRoles = useMemo(() => {
54	    const roles = user?.roles || [];
55	    return roles.map(role =>
56	      typeof role === 'string' ? role.toLowerCase() : ''
57	    );
58	  }, [user?.roles]);
59	
60	  const isDeveloper = useMemo(() => {
61	    return userRoles.includes('developer');
62	  }, [userRoles]);
63	
64	  const isAdmin = useMemo(() => {
65	    return userRoles.includes('admin');
66	  }, [userRoles]);
67	
68	  const isLocationAdmin = useMemo(() => {
69	    return userRoles.includes('location admin');
70	  }, [userRoles]);
71	
72	  const isOwner = useMemo(() => {
73	    return userRoles.includes('owner');
74	  }, [userRoles]);
75	
76	  // Filter tabs based on maintenance state and user role
77	  // Developers: all tabs (minus maintenance)
78	  // Admins, Owners, and Location Admins: meters and locations tabs (minus maintenance)
79	  // Others: only meters tab (minus maintenance)
80	  const availableTabs = useMemo(() => {
81	    const notUnderMaintenance = (tab: (typeof REPORTS_TABS_CONFIG)[number]) =>
82	      tab.available !== false;
83	
84	    if (isDeveloper) {
85	      return REPORTS_TABS_CONFIG.filter(notUnderMaintenance);
86	    }
87	    if (isAdmin || isLocationAdmin || isOwner) {
88	      return REPORTS_TABS_CONFIG.filter(
89	        tab =>
90	          notUnderMaintenance(tab) &&
91	          (tab.id === 'meters' || tab.id === 'locations')
92	      );
93	    }
94	    // Others only see meters tab
95	    return REPORTS_TABS_CONFIG.filter(
96	      tab => notUnderMaintenance(tab) && tab.id === 'meters'
97	    );
98	  }, [isDeveloper, isAdmin, isLocationAdmin, isOwner]);
99	
100	  // All authenticated users have access to reports
101	  const hasAccess = true;
102	  const isLoading = false;
103	
104	  const { activeView, handleTabChange } = useReportsNavigation(availableTabs);
105	
106	  const [refreshing, setRefreshing] = useState(false);
107	
108	  const handleRefresh = useCallback(async () => {
109	    setRefreshing(true);
110	    // Dispatch a custom event that tabs can listen to
111	    window.dispatchEvent(new CustomEvent('refreshReports'));
112	    // Simulate a brief loading state for the button animation
113	    await new Promise(resolve => setTimeout(resolve, 1000));
114	    setRefreshing(false);
115	  }, []);
116	
117	  // ============================================================================
118	  // Computed
119	  // ============================================================================
120	  // Tab content rendering
121	  const tabComponents: Record<ReportView, ReactElement> = {
122	    locations: <ReportsLocationsTabWithErrorHandling />,
123	    machines: <ReportsMachinesTab />,
124	    meters: <ReportsMetersTab />,
125	    'sas-evaluation': (
126	      <div className="flex flex-col items-center justify-center py-20 text-center">
127	        <h3 className="text-xl font-semibold text-gray-500">SAS Evaluation</h3>
128	        <p className="mt-2 text-gray-400">This report view is coming soon.</p>
129	      </div>
130	    ),
131	    'revenue-analysis': (
132	      <div className="flex flex-col items-center justify-center py-20 text-center">
133	        <h3 className="text-xl font-semibold text-gray-500">
134	          Revenue Analysis
135	        </h3>
136	        <p className="mt-2 text-gray-400">This report view is coming soon.</p>
137	      </div>
138	    ),
139	    Cabinets: (
140	      <div className="flex flex-col items-center justify-center py-20 text-center">
141	        <h3 className="text-xl font-semibold text-gray-500">
142	          Cabinets Overview
143	        </h3>
144	        <p className="mt-2 text-gray-400">This report view is coming soon.</p>
145	      </div>
146	    ),
147	    overview: (
148	      <div className="flex flex-col items-center justify-center py-20 text-center">
149	        <h3 className="text-xl font-semibold text-gray-500">
150	          Reports Overview
151	        </h3>
152	        <p className="mt-2 text-gray-400">This report view is coming soon.</p>
153	      </div>
154	    ),
155	  };
156	
157	  const { getTabAnimationProps, currentTabComponent } = useReportsTabContent({
158	    activeView,
159	    animations: REPORTS_ANIMATIONS,
160	    tabComponents,
161	  });
162	
163	  // ============================================================================
164	  // Render Helper Functions
165	  // ============================================================================
166	  /**
167	   * Render the content for the active tab
168	   */
169	  const renderTabContent = (): ReactElement => {
170	    const animationProps = getTabAnimationProps();
171	    const { key, ...restProps } = animationProps;
172	
173	    return (
174	      <AnimatePresence mode="wait">
175	        <motion.div key={key} {...restProps}>
176	          {currentTabComponent}
177	        </motion.div>
178	      </AnimatePresence>
179	    );
180	  };
181	
182	  // ============================================================================
183	  // Computed (Auth & Loading Checks)
184	  // ============================================================================
185	  // Show loading state while authentication is loading
186	  if (isLoading) {
187	    return <ReportsPageAuthLoadingState />;
188	  }
189	
190	  // Show access denied if user has no available tabs
191	  if (!hasAccess) {
192	    return <ReportsPageAccessDeniedState />;
193	  }
194	
195	  // ============================================================================
196	  // Render
197	  // ============================================================================
198	  return (
199	    <PageLayout
200	      headerProps={{
201	        selectedLicencee,
202	        setSelectedLicencee,
203	        disabled: isLoading || refreshing,
204	      }}
205	      showToaster={true}
206	      toasterPosition="top-right"
207	      toasterRichColors={true}
208	      onRefresh={handleRefresh}
209	      refreshing={refreshing}
210	    >
211	      {/* Title and Icon */}
212	      <div className="mb-6 flex items-center gap-3">
213	        <h1 className="text-2xl font-bold text-gray-800 sm:text-3xl">
214	          Reports
215	        </h1>
216	        <Image
217	          src={IMAGES.details}
218	          alt="Reports Icon"
219	          width={32}
220	          height={32}
221	          className="h-6 w-6 sm:h-8 sm:w-8"
222	        />
223	      </div>
224	
225	      {/* Date Filters */}
226	      <ReportsDateFilters />
227	
228	      {/* Navigation */}
229	      <ReportsNavigation
230	        availableTabs={availableTabs}
231	        activeView={activeView}
232	        onTabChange={handleTabChange}
233	      />
234	
235	      {/* Loading Overlay */}
236	      <ReportsPageLoadingOverlay isLoading={isLoading} />
237	
238	      {/* Tab Content */}
239	      {renderTabContent()}
240	    </PageLayout>
241	  );
242	}
