1	/**
2	 * Locations Report API Route
3	 *
4	 * Fetches aggregated reporting data for gaming locations with financial metrics,
5	 * SMIB classification, machine counts, and online status.
6	 *
7	 * Supports filters: licencee, time period, machine type, search, online status,
8	 * pagination, sorting, summary mode, and archived locations.
9	 *
10	 * @module app/api/reports/locations/route
11	 */
12	
13	import {
14	  getUserAccessibleLicenceesFromToken,
15	  getUserLocationFilter,
16	} from '@/app/api/lib/helpers/licenceeFilter';
17	import { getMemberCountsPerLocation } from '@/app/api/lib/helpers/membershipAggregation';
18	import {
19	  applyLocationsCurrencyConversion,
20	  handleSummaryMode,
21	} from '@/app/api/lib/helpers/reports/locations';
22	import {
23	  parseReportLocationsParams,
24	  resolveLicenceeAndDisplayCurrency,
25	  buildLocationMatchStage,
26	  applySmibClassification,
27	  computeLocationMetrics,
28	  getLicenceeJackpotSettings,
29	  buildLocationResults,
30	  applyNonSmibOfflineOverride,
31	  filterAndSortLocations,
32	  createEmptyResponse,
33	} from '@/app/api/lib/helpers/reports/locationReportOperations';
34	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
35	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
36	import { Machine } from '@/app/api/lib/models/machines';
37	import type { GamingMachine } from '@shared/types';
38	import type { LocationDocument } from '@/lib/types/common';
39	import { getGamingDayRangesForLocations } from '@/lib/utils/gamingDayRange';
40	import {
41	  logRouteFetch,
42	  logRouteError,
43	  extractUserFromRequest,
44	} from '@/app/api/lib/utils/routeLogger';
45	import {
46	  getMoneyInScale,
47	  getMoneyOutAndJackpotScale,
48	} from '@/app/api/lib/utils/reviewerScale';
49	import { NextRequest, NextResponse } from 'next/server';
50	
51	export async function GET(req: NextRequest) {
52	  return withApiAuth(
53	    req,
54	    async ({ user: userPayload, userRoles, isAdminOrDev }) => {
55	      const startTime = Date.now();
56	      const functionName = 'GET /api/reports/locations';
57	      const user = extractUserFromRequest(req);
58	
59	      try {
60	        // ============================================================================
61	        // STEP 1: Parse and validate request parameters
62	        // ============================================================================
63	        const { searchParams } = new URL(req.url);
64	        const params = parseReportLocationsParams(searchParams);
65	
66	        if (params.timePeriod === 'Custom' && !params.customStartDate) {
67	          return NextResponse.json(
68	            { error: 'Missing dates' },
69	            { status: 400 }
70	          );
71	        }
72	
73	        // ============================================================================
74	        // STEP 2: Determine accessible locations and display currency
75	        // ============================================================================
76	        const userLocationPermissions =
77	          (userPayload as { assignedLocations?: string[] })
78	            ?.assignedLocations || [];
79	        const userAccessibleLicencees =
80	          await getUserAccessibleLicenceesFromToken();
81	
82	        const { displayCurrency } =
83	          await resolveLicenceeAndDisplayCurrency(
84	            params.licencee,
85	            params.currencyParam,
86	            userAccessibleLicencees
87	          );
88	
89	        const allowedLocationIds = await getUserLocationFilter(
90	          userAccessibleLicencees,
91	          params.licencee || undefined,
92	          userLocationPermissions,
93	          userRoles
94	        );
95	
96	        // ============================================================================
97	        // STEP 3: Build location match stage and fetch locations
98	        // ============================================================================
99	        if (allowedLocationIds !== 'all' && allowedLocationIds.length === 0)
100	          return createEmptyResponse(params.page, params.limit, displayCurrency);
101	
102	        // WOW filter needs location IDs derived from WOW machines (no persisted flag).
103	        let wowLocationIds: string[] | null = null;
104	        if (
105	          params.machineTypeFilter
106	            ?.split(',')
107	            .some(type => type.trim() === 'WowOnly')
108	        ) {
109	          const wowLocs = await Machine.distinct('gamingLocation', {
110	            'meta.dataSync.source': 'wow',
111	            $or: [
112	              { deletedAt: null },
113	              { deletedAt: { $lt: new Date('2025-01-01') } },
114	            ],
115	          });
116	          wowLocationIds = wowLocs.map(id => String(id));
117	        }
118	
119	        const locationMatchStage = buildLocationMatchStage({
120	          showArchived: params.showArchived,
121	          allowedLocationIds,
122	          specificLocations: params.specificLocations,
123	          licencee: params.licencee,
124	          searchTerm: params.searchTerm,
125	          machineTypeFilter: params.machineTypeFilter,
126	          isAdminOrDev,
127	          wowLocationIds,
128	        });
129	
130	        const locations =
131	          await GamingLocations.find(locationMatchStage).lean<
132	            LocationDocument[]
133	          >();
134	
135	        if (searchParams.get('summary') === 'true') {
136	          return await handleSummaryMode(locations, displayCurrency, startTime);
137	        }
138	
139	        const allLocationIds = locations.map(loc => String(loc._id));
140	
141	        // ============================================================================
142	        // STEP 4: Fetch machines and build machine-to-location map
143	        // ============================================================================
144	        const machineMatch: Record<string, unknown> = {
145	          gamingLocation: { $in: allLocationIds },
146	        };
147	        if (!params.showArchived) {
148	          machineMatch.$or = [
149	            { deletedAt: null },
150	            { deletedAt: { $lt: new Date('2025-01-01') } },
151	          ];
152	        } else {
153	          machineMatch.deletedAt = { $gte: new Date('2025-01-01') };
154	        }
155	
156	        const allMachinesData =
157	          await Machine.find(machineMatch).lean<GamingMachine[]>();
158	        const allMachineIds = allMachinesData.map(m => String(m._id));
159	
160	        const locationToMachines = new Map<string, GamingMachine[]>();
161	        allMachinesData.forEach(m => {
162	          const locId = String(m.gamingLocation!);
163	          if (!locationToMachines.has(locId)) locationToMachines.set(locId, []);
164	          locationToMachines.get(locId)!.push(m);
165	        });
166	
167	        // ============================================================================
168	        // STEP 5: SMIB auto-tag and compute metrics
169	        // ============================================================================
170	        await applySmibClassification(
171	          locations,
172	          params.syncAll,
173	          allLocationIds,
174	          locationToMachines
175	        );
176	
177	        const locationRanges = getGamingDayRangesForLocations(
178	          locations.map(loc => ({
179	            _id: String(loc._id),
180	            gameDayOffset: loc.gameDayOffset ?? 8,
181	          })),
182	          params.timePeriod,
183	          params.customStartDate,
184	          params.customEndDate
185	        );
186	
187	        let globalStart = new Date();
188	        let globalEnd = new Date(0);
189	        locationRanges.forEach(range => {
190	          if (range.rangeStart < globalStart) globalStart = range.rangeStart;
191	          if (range.rangeEnd > globalEnd) globalEnd = range.rangeEnd;
192	        });
193	
194	        const metricsMap = await computeLocationMetrics(
195	          allLocationIds,
196	          allMachineIds,
197	          globalStart,
198	          globalEnd,
199	          locationRanges
200	        );
201	
202	        const memberCountMap = await getMemberCountsPerLocation(allLocationIds);
203	        const licenceeIncludeJackpotMap = await getLicenceeJackpotSettings(locations);
204	
205	        const moneyInScale = getMoneyInScale(
206	          userPayload as {
207	            moneyInMultiplier?: number | null;
208	            roles?: string[];
209	            reviewerMultiplierStartTime?: Date | string | null;
210	          },
211	          globalEnd
212	        );
213	        const moneyOutScale = getMoneyOutAndJackpotScale(
214	          userPayload as {
215	            moneyOutAndJackpotMultiplier?: number | null;
216	            roles?: string[];
217	            reviewerMultiplierStartTime?: Date | string | null;
218	          },
219	          globalEnd
220	        );
221	
222	        const locationResults = buildLocationResults(
223	          locations,
224	          locationToMachines,
225	          metricsMap,
226	          memberCountMap,
227	          licenceeIncludeJackpotMap,
228	          moneyInScale,
229	          moneyOutScale
230	        );
231	
232	        // ============================================================================
233	        // STEP 5.5: Non-SMIB offline collection override
234	        // ============================================================================
235	        await applyNonSmibOfflineOverride(locationResults);
236	
237	        // ============================================================================
238	        // STEP 6: Filter, sort, and paginate results
239	        // ============================================================================
240	        const sortedResults = filterAndSortLocations(
241	          locationResults,
242	          params.onlineStatus,
243	          params.sortBy,
244	          params.sortOrder
245	        );
246	
247	        const paginated = sortedResults.slice(params.skip, params.skip + params.limit);
248	        const converted = await applyLocationsCurrencyConversion(
249	          paginated,
250	          params.licencee,
251	          displayCurrency,
252	          isAdminOrDev
253	        );
254	
255	        const duration = Date.now() - startTime;
256	        logRouteFetch(
257	          functionName,
258	          'GET',
259	          '/api/reports/locations',
260	          sortedResults.length,
261	          user,
262	          duration
263	        );
264	
265	        // ============================================================================
266	        // STEP 7: Return final response
267	        // ============================================================================
268	        return NextResponse.json({
269	          data: converted,
270	          pagination: {
271	            page: params.page,
272	            limit: params.limit,
273	            totalCount: sortedResults.length,
274	            totalPages: Math.ceil(sortedResults.length / params.limit),
275	            hasNextPage: params.page < Math.ceil(sortedResults.length / params.limit),
276	            hasPrevPage: params.page > 1,
277	          },
278	          currency: displayCurrency,
279	          converted: isAdminOrDev && (!params.licencee || params.licencee === 'all'),
280	          performance: { totalTime: duration },
281	        });
282	      } catch (err) {
283	        const errorMessage =
284	          err instanceof Error ? err.message : 'Internal server error';
285	        logRouteError(
286	          functionName,
287	          'GET',
288	          '/api/reports/locations',
289	          errorMessage,
290	          user
291	        );
292	        console.error('Reports Locations API Error:', err);
293	        return NextResponse.json(
294	          { error: 'Internal server error' },
295	          { status: 500 }
296	        );
297	      }
298	    }
299	  );
300	}
301

1	import {
2	  getUserLocationFilter,
3	  getUserAccessibleLicenceesFromToken,
4	} from '@/app/api/lib/helpers/licenceeFilter';
5	import {
6	  getAllMachines,
7	  getMachineStats,
8	  getOfflineMachines,
9	  getOverviewMachines,
10	} from '@/app/api/lib/helpers/reports/machines';
11	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
12	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
13	import { TimePeriod } from '@/app/api/lib/types';
14	import { getDatesForTimePeriod } from '@/app/api/lib/utils/dates';
15	import { shouldApplyReviewerMultipliers } from '@/app/api/lib/utils/reviewerScale';
16	import type { GamingLocationDocument } from '@shared/types';
17	import type { CurrencyCode } from '@/shared/types/currency';
18	import {
19	  logRouteFetch,
20	  logRouteError,
21	  extractUserFromRequest,
22	} from '@/app/api/lib/utils/routeLogger';
23	import { NextRequest, NextResponse } from 'next/server';
24	
25	/**
26	 * Main GET handler for fetching machines report
27	 *
28	 * @param {string} type - report sub-type ('stats', 'offline', 'all', or default 'overview')
29	 * @param {string} timePeriod - Time range preset ('Today', '7d', etc.)
30	 * @param {string} licencee - Filter by licencee name
31	 * @param {string} onlineStatus - Filter by connectivity ('online', 'offline', 'all')
32	 * @param {string} search - Search query for machine fields
33	 * @param {string} locationId - Comma-separated location IDs to filter
34	 * @param {string} currency - Target display currency code
35	 * @param {number} page - Page number for pagination
36	 * @param {number} limit - Items per page
37	 * @param {string} startDate - ISO date for custom range start
38	 * @param {string} endDate - ISO date for custom range end
39	 */
40	export async function GET(req: NextRequest) {
41	  return withApiAuth(
42	    req,
43	    async ({ user: userPayload, userRoles, isAdminOrDev }) => {
44	      const startTime = Date.now();
45	      const functionName = 'GET /api/reports/machines';
46	      const user = extractUserFromRequest(req);
47	
48	      try {
49	        // ============================================================================
50	        // STEP 1: Parse and validate request parameters
51	        // Example: GET /api/reports/machines?type=all&locationId=6801f2a3b4c5d6e7f8901234&licencee=9a5db2cb29ffd2d962fd1d91&timePeriod=Yesterday
52	        // ============================================================================
53	        const { searchParams } = new URL(req.url);
54	        const type = searchParams.get('type');
55	        const timePeriod =
56	          (searchParams.get('timePeriod') as TimePeriod) || 'Today';
57	        const licencee = searchParams.get('licencee') || undefined;
58	        const onlineStatus = searchParams.get('onlineStatus') || 'all';
59	        const searchTerm = searchParams.get('search');
60	        const locationId = searchParams.get('locationId');
61	        const displayCurrency =
62	          (searchParams.get('currency') as CurrencyCode) || 'USD';
63	
64	        const page = parseInt(searchParams.get('page') || '1');
65	        const requestedLimit = parseInt(searchParams.get('limit') || '10');
66	        const limit = Math.min(requestedLimit, 500);
67	        const skip = (page - 1) * limit;
68	
69	        let startDate: Date | undefined, endDate: Date | undefined;
70	        if (timePeriod === 'Custom') {
71	          const customStart = searchParams.get('startDate');
72	          const customEnd = searchParams.get('endDate');
73	          if (!customStart || !customEnd)
74	            return NextResponse.json(
75	              { error: 'Missing dates' },
76	              { status: 400 }
77	            );
78	          startDate = customStart.includes('T')
79	            ? new Date(customStart)
80	            : new Date(customStart + 'T00:00:00.000Z');
81	          endDate = customEnd.includes('T')
82	            ? new Date(customEnd)
83	            : new Date(customEnd + 'T00:00:00.000Z');
84	          if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
85	            return NextResponse.json(
86	              { error: 'Invalid dates' },
87	              { status: 400 }
88	            );
89	          }
90	        } else {
91	          const dates = getDatesForTimePeriod(timePeriod);
92	          startDate = dates.startDate;
93	          endDate = dates.endDate;
94	        }
95	
96	        const assignedLocations =
97	          (userPayload as { assignedLocations?: string[] })
98	            ?.assignedLocations || [];
99	        const userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
100	
101	        const allowedLocationIds = await getUserLocationFilter(
102	          userAccessibleLicencees,
103	          licencee,
104	          assignedLocations,
105	          userRoles
106	        );
107	
108	        if (allowedLocationIds !== 'all' && allowedLocationIds.length === 0) {
109	          return NextResponse.json({
110	            data: [],
111	            pagination: { page: 1, limit: 10, totalCount: 0, totalPages: 0 },
112	          });
113	        }
114	
115	        // ============================================================================
116	        // STEP 2: Build match filters
117	        // ============================================================================
118	        const machineMatchStage: Record<string, unknown> = {
119	          $or: [
120	            { deletedAt: null },
121	            { deletedAt: { $lt: new Date('2025-01-01') } },
122	          ],
123	        };
124	
125	        if (allowedLocationIds !== 'all') {
126	          machineMatchStage.gamingLocation = { $in: allowedLocationIds };
127	        }
128	
129	        if (onlineStatus !== 'all') {
130	          const threeMinutesAgo = new Date(Date.now() - 3 * 60 * 1000);
131	
132	          // Fetch aceEnabled location IDs — machines at these locations are always online
133	          const aceEnabledLocs = await GamingLocations.find(
134	            { aceEnabled: true },
135	            { _id: 1 }
136	          ).lean<GamingLocationDocument[]>();
137	          const aceEnabledLocIds = aceEnabledLocs.map(loc => String(loc._id));
138	
139	          if (onlineStatus === 'online') {
140	            // Online = WOW OR (recently active OR aceEnabled location)
141	            const onlineFilter: Record<string, unknown> = {
142	              $or: [
143	                { 'meta.dataSync.source': 'wow' },
144	                { lastActivity: { $gte: threeMinutesAgo } },
145	              ],
146	            };
147	            if (aceEnabledLocIds.length > 0) {
148	              (onlineFilter.$or as Array<Record<string, unknown>>).push({
149	                gamingLocation: { $in: aceEnabledLocIds },
150	              });
151	            }
152	            if (!machineMatchStage.$and) machineMatchStage.$and = [];
153	            (machineMatchStage.$and as Array<Record<string, unknown>>).push(
154	              onlineFilter
155	            );
156	          } else {
157	            // Offline = NOT WOW AND (NOT recently active AND NOT aceEnabled)
158	            if (!machineMatchStage.$and) machineMatchStage.$and = [];
159	            (machineMatchStage.$and as Array<Record<string, unknown>>).push({
160	              'meta.dataSync.source': { $ne: 'wow' },
161	            });
162	            (machineMatchStage.$and as Array<Record<string, unknown>>).push({
163	              $or: [
164	                { lastActivity: { $lt: threeMinutesAgo } },
165	                { lastActivity: { $exists: false } },
166	              ],
167	            });
168	            if (aceEnabledLocIds.length > 0) {
169	              (machineMatchStage.$and as Array<Record<string, unknown>>).push({
170	                gamingLocation: { $nin: aceEnabledLocIds },
171	              });
172	            }
173	          }
174	        }
175	
176	        if (searchTerm?.trim()) {
177	          // Add the search clause under $and so it does NOT overwrite the base
178	          // soft-delete $or filter (which would let deleted machines surface).
179	          if (!machineMatchStage.$and) machineMatchStage.$and = [];
180	          (machineMatchStage.$and as Array<Record<string, unknown>>).push({
181	            $or: [
182	              { serialNumber: { $regex: searchTerm, $options: 'i' } },
183	              { origSerialNumber: { $regex: searchTerm, $options: 'i' } },
184	              { game: { $regex: searchTerm, $options: 'i' } },
185	              { manufacturer: { $regex: searchTerm, $options: 'i' } },
186	              { 'custom.name': { $regex: searchTerm, $options: 'i' } },
187	            ],
188	          });
189	        }
190	
191	        if (locationId && locationId !== 'all') {
192	          const requestedIds = locationId.split(',').filter(id => id.trim());
193	          if (allowedLocationIds !== 'all') {
194	            const accessible = requestedIds.filter(id =>
195	              allowedLocationIds.includes(id)
196	            );
197	            if (accessible.length === 0)
198	              return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
199	            machineMatchStage.gamingLocation =
200	              accessible.length === 1 ? accessible[0] : { $in: accessible };
201	          } else {
202	            machineMatchStage.gamingLocation =
203	              requestedIds.length === 1
204	                ? requestedIds[0]
205	                : { $in: requestedIds };
206	          }
207	        }
208	
209	        const locationMatchStage: Record<string, unknown> = {
210	          $or: [
211	            { deletedAt: null },
212	            { deletedAt: { $lt: new Date('2025-01-01') } },
213	          ],
214	        };
215	
216	        if (allowedLocationIds !== 'all') {
217	          locationMatchStage._id = { $in: allowedLocationIds };
218	        }
219	
220	        if (licencee && licencee !== 'all') {
221	          if (!locationMatchStage.$and) locationMatchStage.$and = [];
222	          (locationMatchStage.$and as Array<Record<string, unknown>>).push({
223	            $or: [{ 'rel.licencee': licencee }],
224	          });
225	        }
226	
227	        // ============================================================================
228	        // STEP 3: Route to appropriate handler
229	        // ============================================================================
230	        const moneyInMult =
231	          (userPayload as { moneyInMultiplier?: number | null })
232	            ?.moneyInMultiplier ?? null;
233	        const moneyOutMult =
234	          (userPayload as { moneyOutAndJackpotMultiplier?: number | null })
235	            ?.moneyOutAndJackpotMultiplier ?? null;
236	        const isReviewer =
237	          (userPayload as { roles?: string[] })?.roles?.includes('reviewer') ??
238	          false;
239	        const shouldApplyReviewerScale = shouldApplyReviewerMultipliers(
240	          userPayload as {
241	            roles?: string[];
242	            reviewerMultiplierStartTime?: Date | string | null;
243	          },
244	          endDate || startDate || null
245	        );
246	        const reviewerMoneyInMult =
247	          isReviewer && shouldApplyReviewerScale ? moneyInMult : null;
248	        const reviewerMoneyOutMult =
249	          isReviewer && shouldApplyReviewerScale ? moneyOutMult : null;
250	        let result;
251	        switch (type) {
252	          case 'stats':
253	            result = await getMachineStats(
254	              machineMatchStage,
255	              locationMatchStage,
256	              startDate,
257	              endDate,
258	              licencee,
259	              displayCurrency,
260	              isAdminOrDev,
261	              timePeriod,
262	              reviewerMoneyInMult,
263	              reviewerMoneyOutMult
264	            );
265	            break;
266	          case 'offline':
267	            result = await getOfflineMachines(
268	              searchParams,
269	              page,
270	              limit,
271	              skip,
272	              startDate,
273	              endDate,
274	              locationMatchStage,
275	              timePeriod,
276	              searchTerm || undefined,
277	              reviewerMoneyInMult,
278	              reviewerMoneyOutMult
279	            );
280	            break;
281	          case 'all':
282	            result = await getAllMachines(
283	              searchParams,
284	              startDate,
285	              endDate,
286	              locationMatchStage,
287	              reviewerMoneyInMult,
288	              reviewerMoneyOutMult
289	            );
290	            break;
291	          default:
292	            result = await getOverviewMachines(
293	              machineMatchStage,
294	              locationMatchStage,
295	              page,
296	              limit,
297	              skip,
298	              startDate,
299	              endDate,
300	              timePeriod,
301	              searchTerm || undefined,
302	              reviewerMoneyInMult,
303	              reviewerMoneyOutMult
304	            );
305	        }
306	
307	        const duration = Date.now() - startTime;
308	        if (duration > 2000)
309	          console.warn(`[Reports Machines API] Slow response: ${duration}ms`);
310	        logRouteFetch(
311	          functionName,
312	          'GET',
313	          '/api/reports/machines',
314	          1,
315	          user,
316	          duration
317	        );
318	
319	        return result;
320	      } catch (err: unknown) {
321	        const errorMessage =
322	          err instanceof Error ? err.message : 'Internal server error';
323	        logRouteError(
324	          functionName,
325	          'GET',
326	          '/api/reports/machines',
327	          errorMessage,
328	          user
329	        );
330	        console.error('Reports Machines API Error:', err);
331	        return NextResponse.json(
332	          { error: 'Internal server error' },
333	          { status: 500 }
334	        );
335	      }
336	    }
337	  );
338	}
