67	/**
68	 * Parse and validate request parameters from URL search params
69	 *
70	 * @param {URLSearchParams} searchParams - URL search parameters
71	 * @returns {ParsedMetersReportParams} Parsed and validated parameters
72	 * @throws Error if required parameters are missing or invalid
73	 */
74	export function parseMetersReportParams(
75	  searchParams: URLSearchParams
76	): ParsedMetersReportParams {
77	  if (!searchParams) {
78	    console.error('[parseMetersReportParams] searchParams is required');
79	    throw new Error('[parseMetersReportParams] searchParams is required');
80	  }
81	  const locations = searchParams.get('locations');
82	  const timePeriod = (searchParams.get('timePeriod') as TimePeriod) || 'Today';
83	  const customStartDate = searchParams.get('startDate');
84	  const customEndDate = searchParams.get('endDate');
85	  const page = parseInt(searchParams.get('page') || '1', 10);
86	  const limit = parseInt(searchParams.get('limit') || '10', 10);
87	  const search = searchParams.get('search') || '';
88	  const licencee = searchParams.get('licencee');
89	  const includeHourlyData = searchParams.get('includeHourlyData') === 'true';
90	
91	  // Validate required parameters
92	  if (!locations) {
93	    throw new Error('Locations parameter is required');
94	  }
95	
96	  // Validate custom date parameters if timePeriod is Custom
97	  if (timePeriod === 'Custom') {
98	    if (!customStartDate || !customEndDate) {
99	      throw new Error('Custom date range requires both startDate and endDate');
100	    }
101	  }
102	
103	  // Determine display currency
104	  // - If currency param is provided, use it (for "All Licencees" mode)
105	  // - Otherwise default to USD
106	  // NOTE: Currency resolution for specific licencee must be done in the API route
107	  // after DB connection, since we need to resolve licencee ID to name
108	  const displayCurrency =
109	    (searchParams.get('currency') as CurrencyCode) || 'USD';
110	
111	  // Parse custom dates if provided
112	  let parsedCustomStart: Date | undefined;
113	  let parsedCustomEnd: Date | undefined;
114	  if (timePeriod === 'Custom' && customStartDate && customEndDate) {
115	    parsedCustomStart = new Date(customStartDate + 'T00:00:00.000Z');
116	    parsedCustomEnd = new Date(customEndDate + 'T00:00:00.000Z');
117	  }
118	
119	  // Parse locations (comma-separated) from request
120	  const requestedLocationList = locations
121	    .split(',')
122	    .map(loc => loc.trim())
123	    .filter(loc => loc !== 'all' && loc !== '');
124	
125	  // Parse machine IDs for hourly data filtering (comma-separated)
126	  const hourlyDataMachineIdsParam = searchParams.get('hourlyDataMachineIds');
127	  const hourlyDataMachineIds = hourlyDataMachineIdsParam
128	    ? hourlyDataMachineIdsParam
129	        .split(',')
130	        .map(id => id.trim())
131	        .filter(id => id !== '')
132	    : undefined;
133	
134	  // Parse granularity parameter
135	  const granularityParam = searchParams.get('granularity');
136	  const granularity =
137	    granularityParam === 'minute' || granularityParam === 'hourly'
138	      ? granularityParam
139	      : undefined;
140	
141	  return {
142	    timePeriod,
143	    customStartDate: parsedCustomStart,
144	    customEndDate: parsedCustomEnd,
145	    page,
146	    limit,
147	    search,
148	    licencee,
149	    displayCurrency,
150	    includeHourlyData,
151	    requestedLocationList,
152	    hourlyDataMachineIds,
153	    granularity,
154	  };
155	}
