157	/**
158	 * Determine the final list of locations to query based on user role and permissions
159	 *
160	 * @param {string[]} requestedLocationList - Locations requested by the user
161	 * @param {string[] | 'all'} allowedLocationIds - Location IDs the user is allowed to access
162	 * @param {boolean} isLocationAdmin - Whether the user is a location admin
163	 * @returns {string[]} Final list of location IDs to query
164	 */
165	export function determineLocationList(
166	  requestedLocationList: string[],
167	  allowedLocationIds: string[] | 'all',
168	  isLocationAdmin: boolean
169	): string[] {
170	  if (!Array.isArray(requestedLocationList) || !allowedLocationIds) {
171	    console.error(
172	      '[determineLocationList] requestedLocationList and allowedLocationIds are required'
173	    );
174	    return [];
175	  }
176	  if (isLocationAdmin) {
177	    // Location admin: only use their assigned locations (ignore request parameter)
178	    if (allowedLocationIds === 'all') {
179	      return [];
180	    }
181	    return allowedLocationIds;
182	  }
183	
184	  if (requestedLocationList.length > 0) {
185	    // Other roles: use requested locations, but filter by allowed locations
186	    if (allowedLocationIds === 'all') {
187	      return requestedLocationList;
188	    }
189	    // Intersect requested locations with allowed locations
190	    return requestedLocationList.filter(loc =>
191	      allowedLocationIds.includes(loc)
192	    );
193	  }
194	
195	  // No locations requested, use all allowed locations
196	  if (allowedLocationIds !== 'all') {
197	    return allowedLocationIds;
198	  }
199	
200	  return [];
201	}
