203	/**
204	 * Fetch location data with gaming day offset information
205	 *
206	 * @param {string[]} locationIds - List of location IDs to fetch
207	 * @returns {Promise<LocationWithGamingDay[]>} Array of location data with gaming day offsets
208	 */
209	export async function fetchLocationData(
210	  locationIds: string[]
211	): Promise<LocationWithGamingDay[]> {
212	  if (!Array.isArray(locationIds)) {
213	    console.error('[fetchLocationData] locationIds must be an array');
214	    return [];
215	  }
216	  if (locationIds.length === 0) {
217	    return [];
218	  }
219	
220	  const locationsData = await GamingLocations.find(
221	    {
222	      _id: { $in: locationIds },
223	      $or: [
224	        { deletedAt: null },
225	        { deletedAt: { $lt: new Date('2025-01-01') } },
226	      ],
227	    },
228	    { _id: 1, name: 1, gameDayOffset: 1, rel: 1, country: 1 }
229	  )
230	    .lean<GamingLocationDocument[]>()
231	    .exec();
232	
233	  return locationsData.map((locationData: Record<string, unknown>) => ({
234	    _id: String(locationData._id),
235	    name: (locationData.name as string) || 'Unknown Location',
236	    gameDayOffset: (locationData.gameDayOffset as number) ?? 8, // Default to 8 AM
237	    rel: (locationData.rel as { licencee?: string }) || undefined,
238	    country: (locationData.country as string) || undefined,
239	  }));
240	}
