242	/**
243	 * Calculate gaming day date ranges for all locations
244	 *
245	 * @param {LocationWithGamingDay[]} locationsData - Location data with gaming day offsets
246	 * @param {TimePeriod} timePeriod - Time period to calculate ranges for
247	 * @param {Date} [customStartDate] - Custom start date (for Custom period)
248	 * @param {Date} [customEndDate] - Custom end date (for Custom period)
249	 * @returns {{ gamingDayRanges: Map<string, { rangeStart: Date; rangeEnd: Date }>; queryStartDate: Date; queryEndDate: Date }} Map of location ID to gaming day range, and overall query date range
250	 */
251	export function calculateGamingDayRanges(
252	  locationsData: LocationWithGamingDay[],
253	  timePeriod: TimePeriod,
254	  customStartDate?: Date,
255	  customEndDate?: Date
256	): {
257	  gamingDayRanges: Map<string, { rangeStart: Date; rangeEnd: Date }>;
258	  queryStartDate: Date;
259	  queryEndDate: Date;
260	} {
261	  if (!Array.isArray(locationsData) || !timePeriod) {
262	    console.error(
263	      '[calculateGamingDayRanges] locationsData and timePeriod are required'
264	    );
265	    return {
266	      gamingDayRanges: new Map(),
267	      queryStartDate: new Date(),
268	      queryEndDate: new Date(),
269	    };
270	  }
271	  const locationsListForGamingDay = locationsData.map(location => ({
272	    _id: location._id,
273	    gameDayOffset: location.gameDayOffset,
274	  }));
275	
276	  const gamingDayRanges = getGamingDayRangesForLocations(
277	    locationsListForGamingDay,
278	    timePeriod,
279	    customStartDate,
280	    customEndDate
281	  );
282	
283	  // Get the earliest start and latest end across all locations
284	  const rangesArray = Array.from(gamingDayRanges.values());
285	  const queryStartDate = new Date(
286	    Math.min(
287	      ...rangesArray.map(gamingDayRange => gamingDayRange.rangeStart.getTime())
288	    )
289	  );
290	  const queryEndDate = new Date(
291	    Math.max(...rangesArray.map(r => r.rangeEnd.getTime()))
292	  );
293	
294	  return {
295	    gamingDayRanges,
296	    queryStartDate,
297	    queryEndDate,
298	  };
299	}
