378	/**
379	 * Get the LAST meter document for each machine within the gaming day range
380	 *
381	 * This aggregation:
382	 * 1. Matches meters within the date range
383	 * 2. Sorts by readAt descending (latest first)
384	 * 3. Groups by machine and uses $first to get the latest document's absolute values
385	 *
386	 * CRITICAL: We use $first (NOT $sum) to get the absolute values from the LAST meter document.
387	 * These are cumulative totals from the meter, not deltas - we want the final state
388	 * at the end of the gaming day.
389	 *
390	 * @param {string[]} machineIds - List of machine IDs to query
391	 * @param {Map<string, { rangeStart: Date; rangeEnd: Date }>} gamingDayRanges - Gaming day date ranges per location
392	 * @returns {Promise<Map<string, MeterAggregationResult>>} Map of machine ID to meter aggregation result
393	 */
394	export async function getLastMeterPerMachine(
395	  machineIds: string[],
396	  gamingDayRanges: Map<string, { rangeStart: Date; rangeEnd: Date }>
397	): Promise<Map<string, MeterAggregationResult>> {
398	  if (!Array.isArray(machineIds) || !(gamingDayRanges instanceof Map)) {
399	    console.error(
400	      '[getLastMeterPerMachine] machineIds and gamingDayRanges are required'
401	    );
402	    return new Map();
403	  }
404	  // Use a map to accumulate results
405	  const metersMap = new Map<string, MeterAggregationResult>();
406	
407	  if (machineIds.length === 0 || gamingDayRanges.size === 0) {
408	    return metersMap;
409	  }
410	
411	  // To ensure we firmly hit the `{ machine: 1, readAt: 1 }` index without triggering
412	  // a massive unindexed full collection scan from `$or`, we will run independent
413	  // optimally indexed queries per location range concurrently!
414	  const promises = Array.from(gamingDayRanges.entries()).map(
415	    async ([locationId, range]) => {
416	      const locResults: Array<Record<string, unknown>> = [];
417	      const metersCursor = Meters.aggregate([
418	        {
419	          $match: {
420	            machine: { $in: machineIds },
421	            location: locationId,
422	            readAt: { $gte: range.rangeStart, $lt: range.rangeEnd },
423	          },
424	        },
425	        // Sort by createdAt descending to get the genuinely latest recorded meter first
426	        // Since the match phase strictly limits results using compound indexes, sorting
427	        // dynamically efficiently scales!
428	        {
429	          $sort: { createdAt: -1 },
430	        },
431	        // Group by machine and take the first (latest) document's absolute values
432	        // CRITICAL: We use $first (NOT $sum) to get the absolute values from the LAST meter document
433	        {
434	          $group: {
435	            _id: '$machine',
436	            drop: { $first: { $ifNull: ['$drop', 0] } },
437	            totalCancelledCredits: {
438	              $first: { $ifNull: ['$totalCancelledCredits', 0] },
439	            },
440	            totalHandPaidCancelledCredits: {
441	              $first: { $ifNull: ['$totalHandPaidCancelledCredits', 0] },
442	            },
443	            coinIn: { $first: { $ifNull: ['$coinIn', 0] } },
444	            coinOut: { $first: { $ifNull: ['$coinOut', 0] } },
445	            totalWonCredits: {
446	              $first: { $ifNull: ['$totalWonCredits', 0] },
447	            },
448	            gamesPlayed: { $first: { $ifNull: ['$gamesPlayed', 0] } },
449	            jackpot: { $first: { $ifNull: ['$jackpot', 0] } },
450	            lastReadAt: { $first: '$readAt' },
451	          },
452	        },
453	      ]).cursor({ batchSize: 1000 });
454	
455	      for await (const doc of metersCursor) {
456	        locResults.push(doc);
457	      }
458	      return locResults;
459	    }
460	  );
461	
462	  const resolvedArrays = await Promise.all(promises);
463	  const metersAggregation = resolvedArrays.flat();
464	
465	  // Populate the map for meter data lookup
466	  metersAggregation.forEach((meterData: Record<string, unknown>) => {
467	    metersMap.set(meterData._id as string, {
468	      _id: meterData._id as string,
469	      drop: (meterData.drop as number) || 0,
470	      totalCancelledCredits: (meterData.totalCancelledCredits as number) || 0,
471	      totalHandPaidCancelledCredits:
472	        (meterData.totalHandPaidCancelledCredits as number) || 0,
473	      coinIn: (meterData.coinIn as number) || 0,
474	      coinOut: (meterData.coinOut as number) || 0,
475	      totalWonCredits: (meterData.totalWonCredits as number) || 0,
476	      gamesPlayed: (meterData.gamesPlayed as number) || 0,
477	      jackpot: (meterData.jackpot as number) || 0,
478	      lastReadAt: (meterData.lastReadAt as Date) || new Date(),
479	    });
480	  });
481	
482	  return metersMap;
483	}
484	
485	/**
486	 * Aggregate meters by hour or minute for chart visualization
487	 *
488	 * This aggregation sums movement fields (deltas) by hour or minute for chart display.
489	 * Unlike the main meter aggregation, this uses $sum to aggregate movement values.
490	 *
491	 * @param {string[]} machineIds - List of machine IDs to query
492	 * @param {Date} queryStartDate - Start date for the query range
493	 * @param {Date} queryEndDate - End date for the query range
494	 * @param {'hourly' | 'minute'} [granularity] - 'hourly' to group by hour, 'minute' to group by minute
495	 * @returns {Promise<HourlyChartData[]>} Array of chart data points (hourly or minute-level)
496	 */
497	export async function getHourlyChartData(
498	  machineIds: string[],
499	  queryStartDate: Date,
500	  queryEndDate: Date,
501	  granularity: 'hourly' | 'minute' = 'hourly'
502	): Promise<HourlyChartData[]> {
503	  if (!Array.isArray(machineIds) || !queryStartDate || !queryEndDate) {
504	    console.error(
505	      '[getHourlyChartData] machineIds, queryStartDate, and queryEndDate are required'
506	    );
507	    return [];
508	  }
509	  // Determine time format based on granularity
510	  const timeFormat = granularity === 'minute' ? '%H:%M' : '%H:00';
511	
512	  // Use cursor for Meters aggregation
513	  const hourlyAggregation: Array<Record<string, unknown>> = [];
514	  const hourlyCursor = Meters.aggregate([
515	    {
516	      $match: {
517	        machine: { $in: machineIds },
518	        // Use $lt (not $lte) for end date because queryEndDate is the start of the next gaming day
519	        // and we want to exclude it (only include up to but not including that time)
520	        readAt: { $gte: queryStartDate, $lt: queryEndDate },
521	      },
522	    },
523	    {
524	      $project: {
525	        machine: 1,
526	        readAt: 1,
527	        'movement.gamesPlayed': 1,
528	        'movement.coinIn': 1,
529	        'movement.coinOut': 1,
530	        // Also use top-level fields as fallback
531	        gamesPlayed: 1,
532	        coinIn: 1,
533	        coinOut: 1,
534	      },
535	    },
536	    {
537	      $addFields: {
538	        hour: {
539	          $dateToString: {
540	            format: timeFormat,
541	            date: '$readAt',
542	          },
543	        },
544	        day: {
545	          $dateToString: {
546	            format: '%Y-%m-%d',
547	            date: '$readAt',
548	          },
549	        },
550	        gamesPlayedValue: {
551	          $ifNull: ['$movement.gamesPlayed', '$gamesPlayed', 0],
552	        },
553	        coinInValue: {
554	          $ifNull: ['$movement.coinIn', '$coinIn', 0],
555	        },
556	        coinOutValue: {
557	          $ifNull: ['$movement.coinOut', '$coinOut', 0],
558	        },
559	      },
560	    },
561	    {
562	      $group: {
563	        _id: {
564	          day: '$day',
565	          hour: '$hour',
566	        },
567	        gamesPlayed: { $sum: '$gamesPlayedValue' },
568	        coinIn: { $sum: '$coinInValue' },
569	        coinOut: { $sum: '$coinOutValue' },
570	      },
571	    },
572	    {
573	      $sort: {
574	        '_id.day': 1,
575	        '_id.hour': 1,
576	      },
577	    },
578	  ]).cursor({ batchSize: 1000 });
579	
580	  for await (const doc of hourlyCursor) {
581	    hourlyAggregation.push(doc);
582	  }
583	
584	  // Only return hours with actual data - filter out hours where all values are zero
585	  return hourlyAggregation
586	    .map((hourData: Record<string, unknown>) => {
587	      const gamesPlayed = (hourData.gamesPlayed as number) || 0;
588	      const coinIn = (hourData.coinIn as number) || 0;
589	      const coinOut = (hourData.coinOut as number) || 0;
590	
591	      return {
592	        day: ((hourData._id as Record<string, unknown>).day as string) || '',
593	        hour: ((hourData._id as Record<string, unknown>).hour as string) || '',
594	        gamesPlayed,
595	        coinIn,
596	        coinOut,
597	      };
598	    })
599	    .filter(
600	      hourlyItem =>
601	        hourlyItem.gamesPlayed > 0 ||
602	        hourlyItem.coinIn > 0 ||
603	        hourlyItem.coinOut > 0
604	    );
605	}
