607	/**
608	 * Format machine ID for display
609	 *
610	 * Display logic:
611	 * - If custom.name and serialNumber are different, show custom.name (serialNumber)
612	 * - Otherwise, use serialNumber if available
613	 * - Otherwise, fall back to custom.name
614	 * - Final fallback: Machine {last 6 chars of _id}
615	 *
616	 * @param {MachineData} machine - Machine data object
617	 * @returns {string} Formatted machine ID string
618	 */
619	function formatMachineId(machine: MachineData): string {
620	  const serialNumber = String(machine.serialNumber || '').trim();
621	  const hasValidSerialNumber = serialNumber.length > 0;
622	  const customName = String(machine.custom?.name || '').trim();
623	
624	  if (customName && hasValidSerialNumber && customName !== serialNumber) {
625	    return `${customName} (${serialNumber})`;
626	  }
627	
628	  if (hasValidSerialNumber) {
629	    return serialNumber;
630	  }
631	
632	  if (customName) {
633	    return customName;
634	  }
635	
636	  // Final fallback
637	  return `Machine ${machine._id.slice(-6)}`;
638	}
