640	/**
641	 * Validate and sanitize meter value
642	 *
643	 * @param {unknown} value - Meter value to validate
644	 * @returns {number} Validated number (0 if invalid or negative)
645	 */
646	function validateMeterValue(value: unknown): number {
647	  const num = Number(value) || 0;
648	  return num >= 0 ? num : 0;
649	}
650	
651	/**
652	 * Transform machine and meter data into report format
653	 *
654	 * @param {MachineData[]} machinesData - Array of machine data
655	 * @param {Map<string, MeterAggregationResult>} metersMap - Map of machine ID to meter aggregation result
656	 * @param {Map<string, string>} locationMap - Map of location ID to location name
657	 * @param {Map<string, boolean>} licenceeSettingsMap - Map of licencee ID to includeJackpot setting
658	 * @param {Map<string, string>} locationLicenceeMap - Map of location ID to licencee ID
659	 * @returns {TransformedMeterData[]} Array of transformed meter report data
660	 */
661	export function transformMeterData(
662	  machinesData: MachineData[],
663	  metersMap: Map<string, MeterAggregationResult>,
664	  locationMap: Map<string, string>,
665	  licenceeSettingsMap: Map<string, boolean>,
666	  locationLicenceeMap: Map<string, string>
667	): TransformedMeterData[] {
668	  if (
669	    !Array.isArray(machinesData) ||
670	    !(metersMap instanceof Map) ||
671	    !(locationMap instanceof Map)
672	  ) {
673	    console.error(
674	      '[transformMeterData] machinesData, metersMap, and locationMap are required'
675	    );
676	    return [];
677	  }
678	  return machinesData.map(machine => {
679	    const locationName =
680	      locationMap.get(machine.gamingLocation) || 'Unknown Location';
681	    const licenceeId = locationLicenceeMap.get(machine.gamingLocation) || '';
682	    const includeJackpot = licenceeSettingsMap.get(licenceeId) || false;
683	
684	    const machineId = formatMachineId(machine);
685	    const machineDocumentId = machine._id;
686	
687	    // Get meter data for this machine
688	    const meterData = metersMap.get(machineDocumentId) || {
689	      _id: machineDocumentId,
690	      drop: 0,
691	      totalCancelledCredits: 0,
692	      totalHandPaidCancelledCredits: 0,
693	      coinIn: 0,
694	      coinOut: 0,
695	      totalWonCredits: 0,
696	      gamesPlayed: 0,
697	      jackpot: 0,
698	      lastReadAt: new Date(),
699	    };
700	
701	    // Extract, validate, and SCALE meter values (Using top-level fields outside movement)
702	    // Terminology Alignment:
703	    // Meters In (Display Name) = Coin In (Total Wagered)
704	    // Meters Out (Display Name) = Total Won Credits (Money Won)
705	    // Bill In (Display Name) = Drop (Cash In Stacker)
706	    // Voucher Out (Display Name) = Total Cancelled Credits
707	    const coinIn = validateMeterValue(meterData.coinIn);
708	    const drop = validateMeterValue(meterData.drop);
709	    const totalCancelledCredits = validateMeterValue(
710	      meterData.totalCancelledCredits
711	    );
712	    const handPaidCredits = validateMeterValue(
713	      meterData.totalHandPaidCancelledCredits
714	    );
715	    const jackpot = validateMeterValue(meterData.jackpot);
716	    const gamesPlayed = validateMeterValue(meterData.gamesPlayed);
717	    const totalWonCredits = validateMeterValue(meterData.totalWonCredits);
718	
719	    const metersIn = coinIn;
720	    const metersOut = totalWonCredits;
721	    const billIn = drop;
722	    // const voucherOut = totalCancelledCredits + jackpot; DEPRICATED
723	    const voucherOut = validateMeterValue(
724	      totalCancelledCredits - handPaidCredits
725	    );
726	    // netGross: Bill In - Meters Out (Total Won) - Jackpots
727	    const netGross = includeJackpot
728	      ? validateMeterValue(billIn - metersOut - jackpot)
729	      : validateMeterValue(billIn - metersOut);
730	
731	    return {
732	      machineId,
733	      metersIn,
734	      metersOut,
735	      jackpot,
736	      billIn,
737	      voucherOut,
738	      attPaidCredits: handPaidCredits,
739	      gamesPlayed,
740	      netGross,
741	      includeJackpot,
742	      location: locationName,
743	      locationId: machine.gamingLocation,
744	      createdAt: (
745	        meterData.lastReadAt ||
746	        machine.lastActivity ||
747	        new Date()
748	      ).toISOString(),
749	      machineDocumentId,
750	      game: machine.game || undefined,
751	      // Include raw fields for export logic
752	      customName: String(machine.custom?.name || '').trim() || undefined,
753	      serialNumber: String(machine.serialNumber || '').trim() || undefined,
754	    };
755	  });
756	}
757	
758	/**
759	 * Filter transformed data by search term
760	 *
761	 * Searches across:
762	 * - machineId (formatted display ID)
763	 * - location name
764	 * - serialNumber
765	 * - custom.name
766	 *
767	 * @param {TransformedMeterData[]} transformedData - Array of transformed meter data
768	 * @param {MachineData[]} machinesData - Original machine data for additional search fields
769	 * @param {string} search - Search term (case-insensitive)
770	 * @returns {TransformedMeterData[]} Filtered array of transformed meter data
771	 */
772	export function filterMeterDataBySearch(
773	  transformedData: TransformedMeterData[],
774	  machinesData: MachineData[],
775	  search: string
776	): TransformedMeterData[] {
777	  if (!Array.isArray(transformedData) || !Array.isArray(machinesData)) {
778	    console.error(
779	      '[filterMeterDataBySearch] transformedData and machinesData are required'
780	    );
781	    return [];
782	  }
783	  if (!search) {
784	    return transformedData;
785	  }
786	
787	  return transformedData.filter(item => {
788	    // Get the original machine data for additional search fields
789	    const machineData = machinesData.find(
790	      m => m._id === item.machineDocumentId
791	    );
792	
793	    const serialNumber = String(machineData?.serialNumber || '').trim();
794	    const customName = String(machineData?.custom?.name || '').trim();
795	    const searchLower = (search || '').toLowerCase();
796	
797	    return (
798	      (item.machineId || '').toLowerCase().includes(searchLower) ||
799	      (item.location || '').toLowerCase().includes(searchLower) ||
800	      serialNumber.toLowerCase().includes(searchLower) ||
801	      customName.toLowerCase().includes(searchLower)
802	    );
803	  });
804	}
805	
806	/**
807	 * Paginate transformed data
808	 *
809	 * @param {TransformedMeterData[]} data - Array of data to paginate
810	 * @param {number} page - Current page number (1-indexed)
811	 * @param {number} limit - Number of items per page
812	 * @returns {{ paginatedData: TransformedMeterData[]; totalCount: number; totalPages: number }} Paginated data and pagination metadata
813	 */
814	export function paginateMeterData(
815	  data: TransformedMeterData[],
816	  page: number,
817	  limit: number
818	): {
819	  paginatedData: TransformedMeterData[];
820	  totalCount: number;
821	  totalPages: number;
822	} {
823	  if (!Array.isArray(data) || !page || !limit) {
824	    console.error('[paginateMeterData] data, page, and limit are required');
825	    return { paginatedData: [], totalCount: 0, totalPages: 0 };
826	  }
827	  const totalCount = data.length;
828	  const totalPages = Math.ceil(totalCount / limit);
829	  const skip = (page - 1) * limit;
830	  const paginatedData = data.slice(skip, skip + limit);
831	
832	  return {
833	    paginatedData,
834	    totalCount,
835	    totalPages,
836	  };
837	}
