1	import { useEffect } from 'react';
2	import { useRouter, useSearchParams } from 'next/navigation';
3	import { toast } from 'sonner';
4	import { useReportsStore } from '@/lib/store/reportsStore';
5	import type { ReportView, ReportTab } from '@/shared/types/reports';
6	
7	/**
8	 * Custom hook for managing reports navigation logic
9	 * Handles URL state management, permission checking, and tab switching
10	 */
11	export function useReportsNavigation(reportsTabsConfig: ReportTab[]) {
12	  // ============================================================================
13	  // State & Hooks
14	  // ============================================================================
15	
16	  const router = useRouter();
17	  const searchParams = useSearchParams();
18	
19	  const { activeView, setActiveView, isLoading, setLoading } =
20	    useReportsStore();
21	
22	  // All tabs are available for authenticated users
23	  const availableTabs = reportsTabsConfig;
24	
25	  // ============================================================================
26	  // Effects
27	  // ============================================================================
28	
29	  /**
30	   * Handle URL state management for tab selection
31	   */
32	  useEffect(() => {
33	    const section = searchParams?.get('section');
34	    if (section === 'machines') {
35	      setActiveView('machines');
36	    } else if (section === 'locations') {
37	      setActiveView('locations');
38	    } else if (section === 'meters') {
39	      setActiveView('meters');
40	    } else {
41	      // Default to first available tab (meters is now the first tab)
42	      const defaultTab =
43	        availableTabs.length > 0 ? availableTabs[0].id : 'meters';
44	      setActiveView(defaultTab as ReportView);
45	    }
46	  }, [searchParams, setActiveView, availableTabs]);
47	
48	  /**
49	   * Ensure user has access to current view, fallback to first available tab
50	   */
51	  useEffect(() => {
52	    if (availableTabs.length > 0) {
53	      const currentTabExists = availableTabs.some(tab => tab.id === activeView);
54	      if (!currentTabExists) {
55	        setActiveView(availableTabs[0].id);
56	      }
57	    }
58	  }, [availableTabs, activeView, setActiveView]);
59	
60	  // ============================================================================
61	  // Handlers
62	  // ============================================================================
63	
64	  /**
65	   * Handle tab change with loading state and permission check
66	   */
67	  const handleTabChange = async (tabId: ReportView) => {
68	    if (tabId === activeView) return;
69	
70	    // Check if user has access to this tab
71	    const targetTab = availableTabs.find(tab => tab.id === tabId);
72	    if (!targetTab) {
73	      toast.error("You don't have permission to access this report");
74	      return;
75	    }
76	
77	    setLoading(true);
78	    setActiveView(tabId);
79	
80	    // Update URL based on tab selection
81	    const sectionMap: Record<ReportView, string> = {
82	      machines: '/reports?section=machines',
83	      locations: '/reports?section=locations',
84	      meters: '/reports?section=meters',
85	      'sas-evaluation': '/reports?section=sas-evaluation',
86	      'revenue-analysis': '/reports?section=revenue-analysis',
87	      Cabinets: '/reports?section=Cabinets',
88	      overview: '/reports?section=overview',
89	    };
90	
91	    router.push(sectionMap[tabId]);
92	
93	    // Simulate loading delay for better UX
94	    setTimeout(() => {
95	      setLoading(false);
96	      toast.success(`Switched to ${targetTab.label} view`);
97	    }, 300);
98	  };
99	
100	  return {
101	    activeView,
102	    availableTabs,
103	    isLoading,
104	    handleTabChange,
105	  };
106	}
