1	/**
2	 * useMetersTabData Hook
3	 *
4	 * Custom hook for managing all data fetching and state for the Meters tab
5	 *
6	 * Features:
7	 * - Location fetching with permission handling
8	 * - Meters data fetching with batch pagination
9	 * - Hourly chart data fetching
10	 * - Top performing machines calculation
11	 * - Search and filtering
12	 * - Chart granularity management
13	 */
14	
15	'use client';
16	
17	import { MutableRefObject } from 'react';
18	import { filterMetersData } from '@/lib/helpers/reports/metersTabHelpers';
19	import { useAbortableRequest } from '@/lib/hooks/useAbortableRequest';
20	import { useDashBoardStore } from '@/lib/store/dashboardStore';
21	import { useReportsStore } from '@/lib/store/reportsStore';
22	import { useUserStore } from '@/lib/store/userStore';
23	import { isAbortError } from '@/lib/utils/errors';
24	import type {
25	  MetersReportData,
26	  MetersReportResponse,
27	} from '@/shared/types/meters';
28	import axios from 'axios';
29	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
30	import { toast } from 'sonner';
31	
32	type HourlyChartData = Array<{
33	  day: string;
34	  hour: string;
35	  gamesPlayed: number;
36	  coinIn: number;
37	  coinOut: number;
38	}>;
39	
40	type Location = {
41	  id: string;
42	  name: string;
43	  sasEnabled: boolean;
44	};
45	
46	type UseMetersTabDataProps = {
47	  itemsPerPage: number;
48	  itemsPerBatch: number;
49	  pagesPerBatch: number;
50	  chartGranularity: 'hourly' | 'minute';
51	  selectedLocations: string[];
52	  searchTerm: string;
53	  debouncedSearchTerm: string;
54	  hasManuallySetGranularityRef: MutableRefObject<boolean>;
55	};
56	
57	export function useMetersTabData({
58	  itemsPerPage,
59	  itemsPerBatch,
60	  pagesPerBatch,
61	  chartGranularity,
62	  selectedLocations,
63	  debouncedSearchTerm,
64	  hasManuallySetGranularityRef,
65	}: UseMetersTabDataProps) {
66	  // ============================================================================
67	  // State & Hooks
68	  // ============================================================================
69	  const makeMetersRequest = useAbortableRequest();
70	  const makeLocationsRequest = useAbortableRequest();
71	  const makeHourlyChartRequest = useAbortableRequest();
72	
73	  const {
74	    selectedLicencee,
75	    activeMetricsFilter,
76	    customDateRange,
77	    displayCurrency,
78	  } = useDashBoardStore();
79	  const { setLoading: setReportsLoading, activeView } = useReportsStore();
80	  const { user } = useUserStore();
81	
82	  // ============================================================================
83	  // State
84	  // ============================================================================
85	  const [allMetersData, setAllMetersData] = useState<MetersReportData[]>([]);
86	  const [locations, setLocations] = useState<Location[]>([]);
87	  const [loading, setLoading] = useState(false);
88	  const [locationsLoading, setLocationsLoading] = useState(true);
89	  const [error, setError] = useState<string | null>(null);
90	  const [hasData, setHasData] = useState(false);
91	  const [currentPage, setCurrentPage] = useState(0);
92	  const [loadedBatches, setLoadedBatches] = useState<Set<number>>(new Set([1]));
93	  const [hourlyChartData, setHourlyChartData] = useState<HourlyChartData>([]);
94	  const [allHourlyChartData, setAllHourlyChartData] = useState<HourlyChartData>(
95	    []
96	  );
97	  const [hourlyChartLoading, setHourlyChartLoading] = useState(false);
98	
99	  const locationsInitialized = useRef(false);
100	  const metersTabFilterInitialized = useRef(false);
101	
102	  // ============================================================================
103	  // Location Admin Logic
104	  // ============================================================================
105	  const isLocationAdmin = useMemo(() => {
106	    const userRoles = user?.roles || [];
107	    return userRoles.some(
108	      role =>
109	        typeof role === 'string' && role.toLowerCase() === 'location admin'
110	    );
111	  }, [user?.roles]);
112	
113	  const [fetchedLocationPermissions, setFetchedLocationPermissions] = useState<
114	    string[]
115	  >([]);
116	
117	  const locationAdminLocations = useMemo(() => {
118	    if (!isLocationAdmin) return [];
119	    let jwtLocations: string[] = [];
120	    if (
121	      Array.isArray(user?.assignedLocations) &&
122	      user.assignedLocations.length > 0
123	    ) {
124	      jwtLocations = user.assignedLocations.map(id => String(id));
125	    }
126	    return jwtLocations.length > 0 ? jwtLocations : fetchedLocationPermissions;
127	  }, [isLocationAdmin, user?.assignedLocations, fetchedLocationPermissions]);
128	
129	  // ============================================================================
130	  // Helper Functions
131	  // ============================================================================
132	  const calculateBatchNumber = useCallback(
133	    (page: number) => {
134	      return Math.floor(page / pagesPerBatch) + 1;
135	    },
136	    [pagesPerBatch]
137	  );
138	
139	  // ============================================================================
140	  // Data Fetching Functions
141	  // ============================================================================
142	  const fetchUserPermissions = useCallback(async () => {
143	    if (!isLocationAdmin || !user?._id) return;
144	
145	    let jwtLocations: string[] = [];
146	    if (
147	      Array.isArray(user?.assignedLocations) &&
148	      user.assignedLocations.length > 0
149	    ) {
150	      jwtLocations = user.assignedLocations.map(id => String(id));
151	    }
152	
153	    if (jwtLocations.length === 0) {
154	      try {
155	        setLocationsLoading(true);
156	        const response = await axios.get('/api/auth/current-user');
157	        if (response.data?.success && response.data?.user?.assignedLocations) {
158	          let serverLocations: string[] = [];
159	          if (
160	            Array.isArray(response.data.user.assignedLocations) &&
161	            response.data.user.assignedLocations.length > 0
162	          ) {
163	            serverLocations = response.data.user.assignedLocations.map(
164	              (id: string) => String(id)
165	            );
166	          }
167	          if (serverLocations.length > 0) {
168	            setFetchedLocationPermissions(serverLocations);
169	          }
170	        }
171	      } catch (err) {
172	        console.error('[MetersTab] Failed to fetch user permissions:', err);
173	      } finally {
174	        setLocationsLoading(false);
175	      }
176	    } else {
177	      setLocationsLoading(false);
178	    }
179	  }, [isLocationAdmin, user?._id, user?.assignedLocations]);
180	
181	  const fetchLocations = useCallback(async () => {
182	    await makeLocationsRequest(async signal => {
183	      try {
184	        setLocationsLoading(true);
185	
186	        if (isLocationAdmin) {
187	          await fetchUserPermissions();
188	        }
189	
190	        const params: Record<string, string> = {};
191	        if (
192	          !isLocationAdmin &&
193	          selectedLicencee &&
194	          selectedLicencee !== 'all'
195	        ) {
196	          params.licencee = selectedLicencee;
197	        }
198	
199	        const response = await axios.get('/api/locations', {
200	          params,
201	          signal,
202	        });
203	
204	        let fetchedLocations: Location[] = [];
205	        if (Array.isArray(response.data?.locations)) {
206	          fetchedLocations = response.data.locations.map(
207	            (loc: {
208	              _id: string;
209	              id?: string;
210	              name: string;
211	              sasEnabled?: boolean;
212	            }) => ({
213	              id: loc.id || String(loc._id),
214	              name: loc.name || '',
215	              sasEnabled: loc.sasEnabled || false,
216	            })
217	          );
218	        }
219	
220	        // Filter locations for location admin
221	        if (isLocationAdmin && locationAdminLocations.length > 0) {
222	          fetchedLocations = fetchedLocations.filter(loc =>
223	            locationAdminLocations.includes(loc.id)
224	          );
225	        }
226	
227	        setLocations(fetchedLocations);
228	      } catch (err: unknown) {
229	        // Silently handle aborted requests - this is expected behavior when switching filters
230	        if (isAbortError(err)) {
231	          return;
232	        }
233	        console.error('Error fetching locations:', err);
234	        toast.error('Failed to load locations', { duration: 3000 });
235	      } finally {
236	        setLocationsLoading(false);
237	      }
238	    });
239	  }, [
240	    isLocationAdmin,
241	    selectedLicencee,
242	    locationAdminLocations,
243	    fetchUserPermissions,
244	    makeLocationsRequest,
245	  ]);
246	
247	  const fetchMetersData = useCallback(
248	    async (batch: number = 1) => {
249	      if (selectedLocations.length === 0) {
250	        setAllMetersData([]);
251	        setHasData(false);
252	        setLoadedBatches(new Set());
253	        setCurrentPage(0);
254	        return;
255	      }
256	
257	      setLoading(true);
258	      setReportsLoading(true);
259	      setError(null);
260	
261	      await makeMetersRequest(async signal => {
262	        // Base query params for the meters API request.
263	        // "locations=Mapau,Stabroek&timePeriod=Yesterday&page=1&limit=50"
264	        const params = new URLSearchParams({
265	          locations: selectedLocations.join(','),
266	          timePeriod: activeMetricsFilter,
267	          page: batch.toString(),
268	          limit: itemsPerBatch.toString(),
269	        });
270	
271	        if (
272	          activeMetricsFilter === 'Custom' &&
273	          customDateRange?.startDate &&
274	          customDateRange?.endDate
275	        ) {
276	          const formatLocalDate = (date: Date) => {
277	            const year = date.getFullYear();
278	            const month = String(date.getMonth() + 1).padStart(2, '0');
279	            const day = String(date.getDate()).padStart(2, '0');
280	            return `${year}-${month}-${day}`;
281	          };
282	          params.append(
283	            'startDate',
284	            formatLocalDate(customDateRange.startDate)
285	          );
286	          params.append('endDate', formatLocalDate(customDateRange.endDate));
287	          // "locations=Mapau,Stabroek&timePeriod=Custom&page=1&limit=50&startDate=2026-01-01&endDate=2026-01-31"
288	        }
289	
290	        if (selectedLicencee && selectedLicencee !== 'all') {
291	          params.append('licencee', selectedLicencee);
292	          // "locations=Mapau,Stabroek&timePeriod=Yesterday&page=1&limit=50&licencee=9a5db2cb29ffd2d962fd1d91"
293	        }
294	
295	        if (displayCurrency) {
296	          params.append('currency', displayCurrency);
297	          // "locations=Mapau,Stabroek&timePeriod=Yesterday&page=1&limit=50&licencee=9a5db2cb29ffd2d962fd1d91&currency=TTD"
298	        }
299	
300	        if (selectedLocations.length > 0) {
301	          params.append('includeHourlyData', 'true');
302	          params.append('granularity', chartGranularity);
303	          // "locations=Mapau,Stabroek&timePeriod=Yesterday&page=1&limit=50&licencee=9a5db2cb29ffd2d962fd1d91&currency=TTD&includeHourlyData=true&granularity=hourly"
304	          setHourlyChartLoading(true);
305	        }
306	
307	        try {
308	          // GET /api/reports/meters?locations=Mapau,Stabroek&timePeriod=Yesterday&page=1&limit=50&licencee=9a5db2cb29ffd2d962fd1d91&currency=TTD&includeHourlyData=true&granularity=hourly
309	          const response = await axios.get<
310	            MetersReportResponse & {
311	              hourlyChartData?: HourlyChartData;
312	            }
313	          >(`/api/reports/meters?${params}`, { signal });
314	
315	          const newMetersData = response.data.data || [];
316	
317	          if (response.data.hourlyChartData) {
318	            setHourlyChartData(response.data.hourlyChartData);
319	            setAllHourlyChartData(response.data.hourlyChartData);
320	
321	            // Note: chartGranularity auto-determination is handled in parent component
322	            // when filtered hourly chart data is fetched
323	          }
324	          setHourlyChartLoading(false);
325	
326	          setAllMetersData(prev => {
327	            const existingIds = new Set(
328	              prev.map(
329	                meterData =>
330	                  meterData.machineId ||
331	                  ((meterData as Record<string, unknown>)._id as string)
332	              )
333	            );
334	            const uniqueNewMeters = newMetersData.filter(
335	              (meterData: MetersReportData) => {
336	                const id =
337	                  meterData.machineId ||
338	                  ((meterData as Record<string, unknown>)._id as string);
339	                return !existingIds.has(id);
340	              }
341	            );
342	            return [...prev, ...uniqueNewMeters];
343	          });
344	        } catch (err: unknown) {
345	          // Silently handle aborted requests - this is expected behavior when switching filters
346	          if (isAbortError(err)) {
347	            setLoading(false);
348	            setReportsLoading(false);
349	            setHourlyChartLoading(false);
350	            return;
351	          }
352	
353	          console.error('Error fetching meters data:', err);
354	          const errorMessage =
355	            (
356	              (
357	                (err as Record<string, unknown>)?.response as Record<
358	                  string,
359	                  unknown
360	                >
361	              )?.data as Record<string, unknown>
362	            )?.error ||
363	            (err as Error)?.message ||
364	            'Failed to load meters data';
365	          setError(errorMessage as string);
366	          setLoading(false);
367	          setReportsLoading(false);
368	          setHourlyChartLoading(false);
369	          toast.error(errorMessage as string, { duration: 3000 });
370	        } finally {
371	          setLoading(false);
372	          setReportsLoading(false);
373	        }
374	      });
375	    },
376	    [
377	      selectedLocations,
378	      activeMetricsFilter,
379	      customDateRange,
380	      selectedLicencee,
381	      displayCurrency,
382	      chartGranularity,
383	      itemsPerBatch,
384	      setReportsLoading,
385	      makeMetersRequest,
386	    ]
387	  );
388	
389	  // ============================================================================
390	  // Effects
391	  // ============================================================================
392	  // Initialize filter to "Yesterday" on mount
393	  useEffect(() => {
394	    if (activeView === 'meters') {
395	      if (!metersTabFilterInitialized.current) {
396	        // This will be handled by parent component
397	        metersTabFilterInitialized.current = true;
398	      }
399	    }
400	  }, [activeView]);
401	
402	  // Initialize locations once on mount
403	  useEffect(() => {
404	    if (!locationsInitialized.current) {
405	      void fetchLocations();
406	      locationsInitialized.current = true;
407	    }
408	  }, [fetchLocations]);
409	
410	  // Refetch locations when licencee changes
411	  useEffect(() => {
412	    if (locationsInitialized.current) {
413	      void fetchLocations();
414	    }
415	  }, [selectedLicencee, fetchLocations]);
416	
417	  // Note: Granularity changes are handled by the main fetchMetersData effect
418	  // which includes chartGranularity in its dependency array, so data is refetched automatically
419	
420	  // Load initial batch on mount and when filters change
421	  useEffect(() => {
422	    if (selectedLocations.length > 0) {
423	      setAllMetersData([]);
424	      setLoadedBatches(new Set([1]));
425	      setCurrentPage(0);
426	      fetchMetersData(1);
427	    }
428	  }, [
429	    selectedLocations,
430	    activeMetricsFilter,
431	    customDateRange,
432	    selectedLicencee,
433	    displayCurrency,
434	    fetchMetersData,
435	  ]);
436	
437	  // Fetch next batch when crossing batch boundaries
438	  useEffect(() => {
439	    if (loading || selectedLocations.length === 0) return;
440	
441	    const currentBatch = calculateBatchNumber(currentPage);
442	    const isLastPageOfBatch = (currentPage + 1) % pagesPerBatch === 0;
443	    const nextBatch = currentBatch + 1;
444	
445	    if (isLastPageOfBatch && !loadedBatches.has(nextBatch)) {
446	      setLoadedBatches(prev => new Set([...prev, nextBatch]));
447	      fetchMetersData(nextBatch);
448	    }
449	
450	    if (!loadedBatches.has(currentBatch)) {
451	      setLoadedBatches(prev => new Set([...prev, currentBatch]));
452	      fetchMetersData(currentBatch);
453	    }
454	  }, [
455	    currentPage,
456	    loading,
457	    fetchMetersData,
458	    itemsPerBatch,
459	    pagesPerBatch,
460	    loadedBatches,
461	    calculateBatchNumber,
462	    selectedLocations.length,
463	  ]);
464	
465	  // Filter meters data based on search term
466	  const filteredMetersData = useMemo(() => {
467	    return filterMetersData(allMetersData, debouncedSearchTerm);
468	  }, [allMetersData, debouncedSearchTerm]);
469	
470	  // Fetch hourly chart data for filtered machines when search changes
471	  useEffect(() => {
472	    if (!selectedLocations.length || !allHourlyChartData.length) {
473	      return;
474	    }
475	
476	    const fetchFilteredHourlyData = async () => {
477	      if (!debouncedSearchTerm.trim()) {
478	        setHourlyChartData(allHourlyChartData);
479	        return;
480	      }
481	
482	      const filteredMachineIds = filteredMetersData
483	        .map(item => {
484	          const itemRecord = item as Record<string, unknown>;
485	          return itemRecord.machineDocumentId as string;
486	        })
487	        .filter((id): id is string => !!id);
488	
489	      if (filteredMachineIds.length === 0) {
490	        setHourlyChartData([]);
491	        return;
492	      }
493	
494	      await makeHourlyChartRequest(async signal => {
495	        try {
496	          setHourlyChartLoading(true);
497	          setReportsLoading(true);
498	          // Base params for filtered hourly chart (search-driven refetch).
499	          // "locations=Mapau,Stabroek&timePeriod=Yesterday&includeHourlyData=true&hourlyDataMachineIds=6801f2a3b4c5d6e7f8901234,6802f3b4c5d6e7f890123456&granularity=hourly"
500	          const params = new URLSearchParams({
501	            locations: selectedLocations.join(','),
502	            timePeriod: activeMetricsFilter,
503	            includeHourlyData: 'true',
504	            hourlyDataMachineIds: filteredMachineIds.join(','),
505	            granularity: chartGranularity,
506	          });
507	
508	          if (
509	            activeMetricsFilter === 'Custom' &&
510	            customDateRange?.startDate &&
511	            customDateRange?.endDate
512	          ) {
513	            const formatLocalDate = (date: Date) => {
514	              const year = date.getFullYear();
515	              const month = String(date.getMonth() + 1).padStart(2, '0');
516	              const day = String(date.getDate()).padStart(2, '0');
517	              return `${year}-${month}-${day}`;
518	            };
519	            params.append(
520	              'startDate',
521	              formatLocalDate(customDateRange.startDate)
522	            );
523	            params.append('endDate', formatLocalDate(customDateRange.endDate));
524	            // "...&startDate=2026-01-01&endDate=2026-01-31"
525	          }
526	
527	          if (selectedLicencee && selectedLicencee !== 'all') {
528	            params.append('licencee', selectedLicencee);
529	            // "...&licencee=9a5db2cb29ffd2d962fd1d91"
530	          }
531	
532	          if (displayCurrency) {
533	            params.append('currency', displayCurrency);
534	            // "...&currency=TTD"
535	          }
536	
537	          // GET /api/reports/meters?locations=Mapau,Stabroek&timePeriod=Yesterday&includeHourlyData=true&hourlyDataMachineIds=6801f2a3b4c5d6e7f8901234,6802f3b4c5d6e7f890123456&granularity=hourly&licencee=9a5db2cb29ffd2d962fd1d91&currency=TTD
538	          const response = await axios.get<{
539	            hourlyChartData?: HourlyChartData;
540	          }>(`/api/reports/meters?${params}`, { signal });
541	
542	          if (response.data.hourlyChartData) {
543	            setHourlyChartData(response.data.hourlyChartData);
544	
545	            // Note: chartGranularity auto-determination is handled in parent component
546	            // when filtered hourly chart data is fetched
547	          } else {
548	            setHourlyChartData([]);
549	          }
550	        } catch (error) {
551	          // Silently handle aborted requests - this is expected behavior when switching filters
552	          if (isAbortError(error)) return; // finally block still runs
553	
554	          console.error('Error fetching filtered hourly chart data:', error);
555	          setHourlyChartData(allHourlyChartData);
556	        } finally {
557	          setHourlyChartLoading(false);
558	          setReportsLoading(false);
559	        }
560	      });
561	    };
562	
563	    fetchFilteredHourlyData();
564	  }, [
565	    debouncedSearchTerm,
566	    filteredMetersData,
567	    selectedLocations,
568	    activeMetricsFilter,
569	    customDateRange,
570	    selectedLicencee,
571	    displayCurrency,
572	    chartGranularity,
573	    allHourlyChartData,
574	    setReportsLoading,
575	    makeHourlyChartRequest,
576	    hasManuallySetGranularityRef,
577	  ]);
578	
579	  // ============================================================================
580	  // Computed
581	  // ============================================================================
582	  // Get items for current page from filtered data.
583	  // filteredMetersData is the full accumulated list across batches, so the
584	  // page offset is simply currentPage * itemsPerPage.
585	  const paginatedMetersData = useMemo(() => {
586	    const startIndex = currentPage * itemsPerPage;
587	    const endIndex = startIndex + itemsPerPage;
588	    return filteredMetersData.slice(startIndex, endIndex);
589	  }, [filteredMetersData, currentPage, itemsPerPage]);
590	
591	  // Calculate total pages based on filtered data
592	  const totalPages = useMemo(() => {
593	    const totalItems = filteredMetersData.length;
594	    const totalPagesFromItems = Math.ceil(totalItems / itemsPerPage);
595	    return totalPagesFromItems > 0 ? totalPagesFromItems : 1;
596	  }, [filteredMetersData.length, itemsPerPage]);
597	
598	  // Update hasData
599	  useEffect(() => {
600	    setHasData(paginatedMetersData.length > 0);
601	  }, [paginatedMetersData.length]);
602	
603	  // ============================================================================
604	  // Return
605	  // ============================================================================
606	  return {
607	    // State
608	    allMetersData,
609	    locations,
610	    loading,
611	    locationsLoading,
612	    error,
613	    hasData,
614	    currentPage,
615	    loadedBatches,
616	    hourlyChartData,
617	    allHourlyChartData,
618	    hourlyChartLoading,
619	    filteredMetersData,
620	    paginatedMetersData,
621	    totalPages,
622	    // Setters
623	    setAllMetersData,
624	    setLocations,
625	    setLoading,
626	    setLocationsLoading,
627	    setError,
628	    setHasData,
629	    setCurrentPage,
630	    setLoadedBatches,
631	    setHourlyChartData,
632	    setAllHourlyChartData,
633	    setHourlyChartLoading,
634	    // Functions
635	    fetchLocations,
636	    fetchMetersData,
637	    calculateBatchNumber,
638	    // Refs
639	    locationsInitialized,
640	    metersTabFilterInitialized,
641	  };
642	}
