23	 */
24	export default function ReportsDateFilters() {
25	  // ============================================================================
26	  // State & Hooks
27	  // ============================================================================
28	  const {
29	    activeMetricsFilter,
30	    setActiveMetricsFilter,
31	    setCustomDateRange,
32	    customDateRange,
33	  } = useDashBoardStore();
34	
35	  const { setDateRange, activeView } = useReportsStore();
36	  const searchParams = useSearchParams();
37	
38	  // ============================================================================
39	  // Computed
40	  // ============================================================================
41	  // Check if we're in location-evaluation or location-revenue sub-tabs
42	  const activeLocationSubTab = searchParams?.get('ltab') || '';
43	  const isLocationEvaluationOrRevenue =
44	    activeView === 'locations' &&
45	    (activeLocationSubTab === 'location-evaluation' ||
46	      activeLocationSubTab === 'location-revenue');
47	
48	  // ============================================================================
49	  // Effects
50	  // ============================================================================
51	  // Reset to "Today" if Quarterly is active but not available on this tab
52	  useEffect(() => {
53	    if (!isLocationEvaluationOrRevenue && activeMetricsFilter === 'Quarterly') {
