55	    }
56	  }, [
57	    activeMetricsFilter,
58	    isLocationEvaluationOrRevenue,
59	    setActiveMetricsFilter,
60	  ]);
61	
62	  // ============================================================================
63	  // Handlers & Helpers
64	  // ============================================================================
65	  // Conditional filter buttons based on active tab
66	  const getTimeFilterButtons = () => {
67	    const baseButtons = [
68	      { label: 'Today', value: 'Today' as TimePeriod },
