84	
85	    baseButtons.push({ label: 'Custom', value: 'Custom' as TimePeriod });
86	
87	    // Show "All Time" for non-meters tabs only
88	    if (activeView !== 'meters') {
89	      baseButtons.push({ label: 'All Time', value: 'All Time' as TimePeriod });
90	    }
91	
92	    return baseButtons;
93	  };
94	
95	  const timeFilterButtons = getTimeFilterButtons();
96	
97	  /**
98	   * Handle custom date selection from ModernCalendar
99	   */
100	  const handleCustomDateSelect = (
101	    date: { from?: Date; to?: Date } | undefined
102	  ) => {
103	    if (!date?.from) return;
104	
105	    // For meters tab (single mode), use the same date for start and end
106	    if (activeView === 'meters') {
107	      const startDate = new Date(date.from);
108	      startDate.setHours(0, 0, 0, 0);
109	      setCustomDateRange({
110	        startDate: startDate,
111	        endDate: startDate, // Use the same date object or one with matched time
112	      });
113	      setDateRange(startDate, startDate);
114	      setActiveMetricsFilter('Custom');
115	    } else if (date.from && date.to) {
116	      // For range mode (other tabs), use the provided range
117	      setCustomDateRange({
118	        startDate: date.from,
119	        endDate: date.to,
120	      });
121	      setDateRange(date.from, date.to);
122	      setActiveMetricsFilter('Custom');
123	    }
124	  };
125	
126	  /**
127	   * Handle filter button clicks for predefined periods
128	   */
129	  const handleFilterClick = (filter: TimePeriod) => {
130	    // Update reports store based on filter.
131	    // Each case derives its dates from a fresh `Date` so we never mutate or
132	    // alias a shared value across branches.
133	    let startDate: Date, endDate: Date;
134	
135	    switch (filter) {
136	      case 'Today': {
137	        const base = new Date();
138	        startDate = new Date(base);
139	        startDate.setHours(0, 0, 0, 0);
140	        endDate = new Date(base);
141	        endDate.setHours(23, 59, 59, 999);
142	        break;
143	      }
144	      case 'Yesterday': {
145	        const base = new Date();
146	        base.setDate(base.getDate() - 1);
147	        startDate = new Date(base);
148	        startDate.setHours(0, 0, 0, 0);
149	        endDate = new Date(base);
150	        endDate.setHours(23, 59, 59, 999);
151	        break;
152	      }
153	      case '7d':
154	      case 'last7days': {
155	        const start = new Date();
156	        start.setDate(start.getDate() - 7);
157	        startDate = start;
158	        endDate = new Date();
159	        break;
160	      }
161	      case '30d':
162	      case 'last30days': {
163	        const start = new Date();
164	        start.setDate(start.getDate() - 30);
165	        startDate = start;
166	        endDate = new Date();
167	        break;
168	      }
169	      case 'Quarterly': {
