180	        // For "All Time", set a very wide range
181	        startDate = new Date(0); // Epoch start
182	        endDate = new Date();
183	        break;
184	      default: {
185	        const base = new Date();
186	        startDate = new Date(base);
187	        startDate.setHours(0, 0, 0, 0);
188	        endDate = new Date(base);
189	        endDate.setHours(23, 59, 59, 999);
190	      }
191	    }
192	
193	    if (filter !== 'Custom') {
194	      setDateRange(startDate, endDate);
195	    }
