216	              <option key={filter.value} value={filter.value}>
217	                {filter.label}
218	              </option>
219	            ))}
220	          </select>
221	
222	          {/* MUI Custom Date Picker for Mobile */}
223	          {activeMetricsFilter === 'Custom' && (
224	            <div className="mt-2 w-full">
225	              <MuiDateCalendar
226	                date={customDateRange?.startDate}
227	                endDate={customDateRange?.endDate}
228	                onSelect={range => {
229	                  if (range) handleCustomDateSelect(range);
230	                }}
231	                mode={activeView === 'meters' ? 'single' : 'range'}
232	                hideLabels={true}
233	                showTime={activeView !== 'meters'}
234	                buttonLabel="Generate Report"
235	                className="w-full"
236	              />
237	            </div>
238	          )}
239	        </div>
240	
241	        {/* md and above: Filter buttons */}
242	        <div className="hidden flex-wrap items-center gap-2 md:flex">
243	          {timeFilterButtons
244	            .filter(filter => filter.value !== 'Custom')
245	            .map(filter => (
246	              <Button
247	                key={filter.value}
248	                className={`rounded-md px-3 py-1 text-sm transition-colors ${
249	                  activeMetricsFilter === filter.value
250	                    ? 'bg-buttonActive text-white'
251	                    : 'bg-button text-white hover:bg-button/90'
252	                }`}
253	                onClick={() => handleFilterClick(filter.value)}
254	              >
255	                {filter.label}
256	              </Button>
257	            ))}
258	
259	          {/* MUI Custom Date Picker for Desktop */}
260	          <Popover>
261	            <PopoverTrigger asChild>
