1	/**
2	 * Currency Conversion Helper for Meters Report
3	 *
4	 * This module handles currency conversion for the meters report when viewing
5	 * "All Licencees" mode as an Admin or Developer.
6	 *
7	 * @module app/api/lib/helpers/metersReportCurrency
8	 */
9	
10	import {
11	  convertFromUSD,
12	  convertToUSD,
13	  getCountryCurrency,
14	} from '@/lib/helpers/rates';
15	import type { CurrencyCode } from '@/shared/types/currency';
16	// Note: Db type from mongodb not imported to avoid mongoose/mongodb version mismatch
17	import { Countries } from '@/app/api/lib/models/countries';
18	import { Licencee } from '@/app/api/lib/models/licencee';
19	import type { CountryDocument, LicenceeDocument } from '@/shared/types';
20	import type { LocationWithGamingDay, TransformedMeterData } from './meters';
21	
22	/**
23	 * Location details for currency determination
24	 */
25	type LocationDetails = {
26	  licencee: string | null;
27	  country: string | null;
28	};
29	
30	/**
31	 * Build maps for currency conversion lookup
32	 *
33	 * @param db - MongoDB database instance
34	 * @param locationsData - Location data with licencee and country info
35	 * @returns Maps for licencee-to-country and location-to-details lookup
36	 */
37	export async function buildCurrencyMaps(
38	  locationsData: LocationWithGamingDay[]
39	): Promise<{
40	  licenceeMap: Map<string, string>;
41	  countryNameMap: Map<string, string>;
42	  locationDetailsMap: Map<string, LocationDetails>;
43	}> {
44	  if (!Array.isArray(locationsData)) {
45	    console.error('[buildCurrencyMaps] locationsData is required');
46	    return {
47	      licenceeMap: new Map(),
48	      countryNameMap: new Map(),
49	      locationDetailsMap: new Map(),
50	    };
51	  }
52	
53	  // Fetch licencee mappings
54	  const allLicencees = await Licencee.find({}, { _id: 1, name: 1, country: 1 })
55	    .lean<LicenceeDocument[]>()
56	    .exec();
57	
58	  const licenceeMap = new Map<string, string>();
59	  allLicencees.forEach((lic: Record<string, unknown>) => {
60	    licenceeMap.set(String(lic._id), String(lic.country));
61	  });
62	
63	  // Fetch country names from country IDs
64	  const countryIds = locationsData
65	    .map(loc => loc.country)
66	    .filter((id): id is string => !!id);
67	
68	  const countries = await Countries.find(
69	    { _id: { $in: countryIds } },
70	    { _id: 1, name: 1 }
71	  )
72	    .lean<CountryDocument[]>()
73	    .exec();
74	
75	  const countryNameMap = new Map<string, string>();
76	  countries.forEach((country: Record<string, unknown>) => {
77	    countryNameMap.set(String(country._id), country.name as string);
78	  });
79	
80	  // Build location details map
81	  const locationDetailsMap = new Map<string, LocationDetails>();
82	  locationsData.forEach(loc => {
83	    const countryId = loc.country;
84	    const countryName = countryId ? countryNameMap.get(countryId) : null;
85	
86	    locationDetailsMap.set(loc._id, {
87	      licencee: loc.rel?.licencee || null,
88	      country: countryName || null,
89	    });
90	  });
91	
92	  return {
93	    licenceeMap,
94	    countryNameMap,
95	    locationDetailsMap,
96	  };
97	}
98	
99	/**
100	 * Determine the native currency for a location
101	 *
102	 * @param locationDetails - Location details with licencee and country info
103	 * @param licenceeMap - Map of licencee ID to country ID
104	 * @returns Native currency code for the location
105	 */
106	function getNativeCurrencyForLocation(
107	  locationDetails: LocationDetails | undefined,
108	  licenceeMap: Map<string, string>
109	): CurrencyCode {
110	  if (!locationDetails || !licenceeMap) {
111	    console.error(
112	      '[getNativeCurrencyForLocation] locationDetails and licenceeMap are required'
113	    );
114	    return 'USD';
115	  }
116	  if (!locationDetails) {
117	    return 'USD';
118	  }
119	
120	  if (locationDetails.licencee) {
121	    const licenceeCountry = licenceeMap.get(locationDetails.licencee);
122	    if (licenceeCountry) {
123	      return getCountryCurrency(licenceeCountry);
124	    }
125	  }
126	
127	  if (locationDetails.country) {
128	    return getCountryCurrency(locationDetails.country);
129	  }
130	
131	  return 'USD';
132	}
133	
134	/**
135	 * Convert financial fields from native currency to display currency
136	 *
137	 * @param item - Meter data item to convert
138	 * @param nativeCurrency - Native currency of the location
139	 * @param displayCurrency - Target display currency
140	 * @returns Converted meter data item
141	 */
142	function convertMeterDataCurrency(
143	  item: TransformedMeterData,
144	  nativeCurrency: CurrencyCode,
145	  displayCurrency: CurrencyCode
146	): TransformedMeterData {
147	  if (!item || !nativeCurrency || !displayCurrency) {
148	    console.error(
149	      '[convertMeterDataCurrency] item, nativeCurrency, and displayCurrency are required'
150	    );
151	    return item || ({} as TransformedMeterData);
152	  }
153	  // Only convert if native currency differs from display currency
154	  if (nativeCurrency === displayCurrency) {
155	    return item;
156	  }
157	
158	  const convertedItem = { ...item };
159	
160	  // Convert financial fields: native → USD → displayCurrency
161	  const financialFields: Array<keyof TransformedMeterData> = [
162	    'billIn',
163	    'metersIn',
164	    'metersOut',
165	    'jackpot',
166	    'voucherOut',
167	    'attPaidCredits',
168	    'netGross',
169	  ];
170	
171	  financialFields.forEach(field => {
172	    const value = convertedItem[field];
173	    if (typeof value === 'number') {
174	      // Step 1: Convert from native currency to USD
175	      const usdValue = convertToUSD(value, nativeCurrency);
176	      // Step 2: Convert from USD to display currency
177	      (convertedItem as Record<string, unknown>)[field] = convertFromUSD(
178	        usdValue,
179	        displayCurrency
180	      );
181	    }
182	  });
183	
184	  return convertedItem;
185	}
186	
187	/**
188	 * Apply currency conversion to all meter data items
189	 *
190	 * @param data - Array of meter data items
191	 * @param locationDetailsMap - Map of location ID to location details
192	 * @param licenceeMap - Map of licencee name to country ID
193	 * @param displayCurrency - Target display currency
194	 * @returns Array of converted meter data items
195	 */
196	export function applyCurrencyConversion(
197	  data: TransformedMeterData[],
198	  locationDetailsMap: Map<string, LocationDetails>,
199	  licenceeMap: Map<string, string>,
200	  displayCurrency: CurrencyCode
201	): TransformedMeterData[] {
202	  if (
203	    !Array.isArray(data) ||
204	    !locationDetailsMap ||
205	    !licenceeMap ||
206	    !displayCurrency
207	  ) {
208	    console.error(
209	      '[applyCurrencyConversion] data, locationDetailsMap, licenceeMap, and displayCurrency are required'
210	    );
211	    return data || [];
212	  }
213	
214	  return data.map(item => {
215	    const locationDetails = locationDetailsMap.get(item.locationId);
216	    const nativeCurrency = getNativeCurrencyForLocation(
217	      locationDetails,
218	      licenceeMap
219	    );
220	
221	    return convertMeterDataCurrency(item, nativeCurrency, displayCurrency);
222	  });
223	}
